fn NfaNameIN_SINGLE_LINE_COMMENTIndex0(ch: u32, next_states: &mut [u64], valid_types: Option<&HashSet<TokenType>>, already_matched: &mut HashSet<TokenType>) -> Option<TokenType> {
    let mut matched_type: Option<TokenType> = None;
    if ch == 13
 {
        bitset_set(next_states, 1);
    }
    if ch <= 1114111
 {
        if valid_types.map_or(true, |vt| vt.contains(&TokenType::ANY_CHAR)) {
            matched_type = Some(TokenType::ANY_CHAR);
        }
    }
    if ch == 10
 {
        if valid_types.map_or(true, |vt| vt.contains(&TokenType::LINE_COMMENT)) {
            matched_type = Some(TokenType::LINE_COMMENT);
        }
    }
    if ch == 13
 {
        if valid_types.map_or(true, |vt| vt.contains(&TokenType::LINE_COMMENT)) {
            matched_type = Some(TokenType::LINE_COMMENT);
        }
    }
    matched_type
}

